challenges.solution:
uniform vec3 u_light;
in vec3 v_normal;
in vec3 v_position;
out vec4 fragColor;

void main() {
    vec3 N = normalize(v_normal);
    vec3 L = normalize(u_light);
    vec3 V = normalize(vec3(0.0, 0.0, 3.0) - v_position);

    float ambient = 0.08;
    float diff = max(0.0, dot(N, L));

    vec3 H = normalize(L + V);
    float spec = pow(max(0.0, dot(N, H)), 64.0);

    vec3 baseColor = vec3(1.0, 0.5, 0.1);
    vec3 col = baseColor * (ambient + diff) + vec3(1.0) * spec;
    fragColor = vec4(col, 1.0);
}

